klockan() { printf %b "\e[?25l"; while :; do printf %b "\ec\e[$((LINES/2-18))B"; ok "$(date +%A)"; printf %b "\e[4A"; ok "$(date +%R)"; gum style --border none --width $((COLUMNS)) --align center --padding "0" --border-foreground 8 "$(gum style --border normal --padding "1 2" --border-foreground 8 "$(while :; do ff="$(fortune)"; [ ${#ff} -lt 155 ] && printf %b "$ff" && break; done)")"||break; printf %b "\e[?25l"; read -sen1 -t44 kk; [ $? -lt 120 ] && printf %b "\e[?25h\ec" && break; done; }; 
